"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   seoBlogPosts: () => (/* binding */ seoBlogPosts)\n/* harmony export */ });\nconst seoBlogPosts = [\n    {\n        slug: \"how-are-ivf-embryos-transported-internationally\",\n        title: \"How Are IVF Embryos Transported Internationally?\",\n        seoTitle: \"How Are IVF Embryos Transported Internationally? | ARKGlobal\",\n        metaDescription: \"Learn how IVF embryos are transported internationally — from dry shippers and IATA certification to customs clearance and real-time cold chain monitoring.\",\n        category: \"Patient Guides\",\n        keywords: [\n            \"how are IVF embryos transported\",\n            \"international embryo transport\",\n            \"IVF shipping process\",\n            \"cryo embryo courier\"\n        ],\n        publishedDate: \"2025-11-15\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"International IVF embryo transport is a highly specialised logistics process. Unlike standard medical courier services, moving frozen embryos across borders requires IATA-certified handling, cryogenic dry shippers, strict documentation, and uninterrupted cold chain monitoring.\\n\\nHere is exactly how the process works — step by step.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Step 1: Documentation and Clinic Coordination\",\n                text: \"Before any shipment, both the sending and receiving fertility clinics must confirm readiness. Required documents typically include:\",\n                items: [\n                    \"Written consent from the patient(s)\",\n                    \"Clinic release letter confirming sample viability\",\n                    \"Receiving clinic acceptance letter\",\n                    \"Medical records and freezing protocol documentation\",\n                    \"Import permit for the destination country (where required)\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"Step 2: Loading Into a Dry Shipper\",\n                text: \"Embryos are transferred from the clinic's storage tank into a cryogenic dry shipper — a vacuum-insulated vessel that uses liquid nitrogen vapour to maintain temperatures below -150°C. The loading is supervised by the clinic's embryologist, and the vessel is sealed and logged before the courier takes custody.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Step 3: Hand-Carry Air Transport\",\n                text: \"A trained, IATA P650-certified courier hand-carries the dry shipper as cabin baggage on commercial flights. This avoids cargo hold temperature extremes and eliminates handoffs to unqualified handlers. Routes are planned to minimise layover time.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Step 4: Real-Time Temperature Monitoring\",\n                text: \"Throughout the journey, a 5G-enabled data logger continuously records and transmits the internal temperature. Patients, sending clinics, and receiving clinics can monitor conditions in real time from anywhere in the world.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Step 5: Customs and Delivery\",\n                text: \"At the destination, the courier clears customs with pre-arranged documentation and delivers the dry shipper directly to the receiving clinic's embryology team. A complete temperature log is provided as part of the handover.\"\n            },\n            {\n                type: \"cta\",\n                text: \"Planning an international embryo transfer? ARKGlobal handles the entire process — from clinic coordination to door-to-door delivery with real-time monitoring.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"How are IVF embryos transported internationally?\",\n                answer: \"Embryos are loaded into IATA-certified dry shippers, hand-carried by trained couriers on commercial flights, monitored in real time, and delivered door-to-door to the receiving clinic.\"\n            },\n            {\n                question: \"How long does international embryo transport take?\",\n                answer: \"Most shipments complete within 24–48 hours. Dry shippers maintain safe temperatures for 5–7 days.\"\n            }\n        ]\n    },\n    {\n        slug: \"what-is-a-cryogenic-dry-shipper\",\n        title: \"What Is a Cryogenic Dry Shipper?\",\n        seoTitle: \"What Is a Cryogenic Dry Shipper? | Cryo Transport Explained\",\n        metaDescription: \"A cryogenic dry shipper keeps IVF samples below -150°C using nitrogen vapour — safe for air travel. Learn how dry shippers work and why they matter.\",\n        category: \"Education\",\n        keywords: [\n            \"cryogenic dry shipper\",\n            \"dry shipper IVF\",\n            \"liquid nitrogen vapour transport\",\n            \"cryo vessel\"\n        ],\n        publishedDate: \"2025-11-20\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"If you're researching how frozen embryos, eggs, or sperm are shipped internationally, you'll encounter the term \\\"dry shipper\\\" constantly. Understanding what it is — and why it matters — is essential for anyone planning a cryogenic shipment.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Definition: What Is a Dry Shipper?\",\n                text: \"A cryogenic dry shipper is a vacuum-insulated container designed to transport biological samples at cryogenic temperatures (below -150°C) without containing free-flowing liquid nitrogen. Instead, liquid nitrogen is absorbed into a porous material inside the vessel, which slowly releases cold nitrogen vapour to maintain extreme cold.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Dry Shipper vs. Liquid Nitrogen Dewar\",\n                text: \"The key difference:\",\n                items: [\n                    \"Dry shipper: Uses nitrogen vapour only — safe for commercial air travel as cabin baggage\",\n                    \"Liquid nitrogen dewar: Contains liquid nitrogen — classified as hazardous material with strict airline restrictions\",\n                    \"Dry shipper hold time: Typically 5–7 days below -150°C without refilling\",\n                    \"Dewar hold time: Longer, but impractical for most international patient shipments\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"Why Dry Shippers Are Used for IVF Transport\",\n                text: \"Vitrified embryos and eggs must remain below -150°C to stay in a stable glass-like state. A quality dry shipper provides a sealed, temperature-stable environment that protects against external heat while being portable enough for a courier to hand-carry through airports and customs.\"\n            },\n            {\n                type: \"cta\",\n                text: \"ARKGlobal uses IATA-certified MVE dry shippers with 5G temperature monitoring on every shipment. Contact us to discuss your transport requirements.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"What is a cryogenic dry shipper?\",\n                answer: \"A vacuum-insulated vessel that uses liquid nitrogen vapour to keep biological samples below -150°C, safe for commercial air travel.\"\n            },\n            {\n                question: \"How long does a dry shipper stay cold?\",\n                answer: \"Typically 5–7 days below -150°C when fully charged, depending on the model and ambient conditions.\"\n            }\n        ]\n    },\n    {\n        slug: \"can-frozen-embryos-be-transported-safely\",\n        title: \"Can Frozen Embryos Be Transported Safely?\",\n        seoTitle: \"Can Frozen Embryos Be Transported Safely? | Expert Answer\",\n        metaDescription: \"Yes — frozen embryos can be transported safely with IATA-certified couriers and dry shippers. Learn what makes embryo shipping safe and what risks to avoid.\",\n        category: \"Patient Guides\",\n        keywords: [\n            \"frozen embryo transport safety\",\n            \"is embryo shipping safe\",\n            \"embryo viability transport\",\n            \"safe embryo courier\"\n        ],\n        publishedDate: \"2025-12-01\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"The short answer is yes — frozen embryos can be transported safely internationally. Thousands of embryo transfers between clinics occur every year worldwide. The key is using the right equipment, the right courier, and the right protocols.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Why Embryo Transport Is Safe When Done Correctly\",\n                text: \"Vitrified embryos are remarkably stable at cryogenic temperatures. As long as they remain below -150°C, they can theoretically remain viable indefinitely. Professional transport maintains this temperature using:\",\n                items: [\n                    \"IATA P650-certified dry shippers\",\n                    \"Hand-carry courier service (no cargo hold exposure)\",\n                    \"Real-time continuous temperature monitoring\",\n                    \"Pre-planned routes with minimal layovers\",\n                    \"Contingency protocols for delays\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"What Makes Embryo Transport Unsafe\",\n                text: \"Risks arise when shortcuts are taken:\",\n                items: [\n                    \"Using an uncertified courier without IATA training\",\n                    \"Shipping in cargo hold without proper handling protocols\",\n                    \"No real-time temperature monitoring (paper strips only)\",\n                    \"Missing import permits causing multi-day customs holds\",\n                    \"Multiple handoffs to non-specialist handlers\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"How to Verify Your Courier Is Qualified\",\n                text: \"Before booking, ask: Are you IATA P650 certified? Do you use dry shippers? Can I monitor temperature in real time? Have you shipped to my destination before? A professional cryo courier will answer all of these clearly.\"\n            },\n            {\n                type: \"cta\",\n                text: \"ARKGlobal maintains a 100% cold chain success rate. Every shipment is monitored in real time from door to door.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"Is embryo transportation safe?\",\n                answer: \"Yes, with an IATA-certified courier, dry shipper, and real-time monitoring. Risks increase significantly with uncertified handlers or broken cold chains.\"\n            },\n            {\n                question: \"Can temperature changes damage embryos?\",\n                answer: \"Yes. If vitrified embryos warm above approximately -130°C, ice crystals can form and reduce viability — often without visible damage until thaw.\"\n            }\n        ]\n    },\n    {\n        slug: \"international-regulations-ivf-shipping\",\n        title: \"International Regulations for IVF Shipping\",\n        seoTitle: \"International Regulations for IVF Shipping | Compliance Guide\",\n        metaDescription: \"IVF shipping is governed by IATA P650, national biosecurity laws, and tissue directives. Understand the regulations for embryo transport worldwide.\",\n        category: \"Education\",\n        keywords: [\n            \"IVF shipping regulations\",\n            \"embryo transport laws\",\n            \"IATA P650 regulations\",\n            \"international fertility compliance\"\n        ],\n        publishedDate: \"2025-12-10\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"Moving frozen embryos, eggs, or sperm across international borders involves multiple layers of regulation. Understanding these requirements helps patients and clinics plan shipments without costly delays.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"IATA P650 — The Air Transport Standard\",\n                text: \"IATA Packing Instruction P650 governs how Category B biological substances are packaged and transported by air. For cryogenic specimens, this means dry shippers, proper labelling, secondary containment, and courier training certification.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"National Biosecurity and Import Laws\",\n                text: \"Each destination country has its own import requirements:\",\n                items: [\n                    \"Australia: DAFF import permit required (4–8 weeks processing)\",\n                    \"United Kingdom: HTA licensing and import notification\",\n                    \"United States: FDA and CDC regulations for reproductive tissue\",\n                    \"UAE: Ministry of Health import approval\",\n                    \"EU countries: EU Tissue and Cells Directives compliance\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"Local ART Regulations\",\n                text: \"Assisted reproductive technology laws vary across Southeast Asia. Malaysia, Singapore, Thailand, and Indonesia each have different rules on who can access IVF, donor gametes, and cross-border transfers. Your fertility clinic will advise on eligibility.\"\n            },\n            {\n                type: \"cta\",\n                text: \"ARKGlobal manages import permits, customs documentation, and regulatory compliance for every destination. Contact us before your planned transfer date.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"What regulations govern IVF shipping?\",\n                answer: \"IATA P650 for air transport, national biosecurity/import laws, EU Tissue Directives where applicable, and local ART regulations in each country.\"\n            },\n            {\n                question: \"Do I need an import permit to ship embryos?\",\n                answer: \"Most countries require one. Australia, the UK, and the US have formal permit processes that should begin 4–8 weeks before shipment.\"\n            }\n        ]\n    },\n    {\n        slug: \"choosing-the-right-ivf-courier\",\n        title: \"Choosing the Right IVF Courier\",\n        seoTitle: \"Choosing the Right IVF Courier | What to Look For\",\n        metaDescription: \"How to choose an IVF courier: IATA P650 certification, dry shippers, real-time monitoring, and destination experience. A practical checklist for patients.\",\n        category: \"Patient Guides\",\n        keywords: [\n            \"IVF courier\",\n            \"embryo courier service\",\n            \"choosing cryo courier\",\n            \"certified embryo transport\"\n        ],\n        publishedDate: \"2026-01-05\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"Choosing the right IVF courier is one of the most important decisions in your fertility journey. Your embryos or eggs cannot be replaced — so the courier you select must have proven cryogenic expertise, not just general medical logistics experience.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Essential Criteria Checklist\",\n                text: \"Before booking any cryo courier, verify:\",\n                items: [\n                    \"IATA P650 certification — ask to see the certificate\",\n                    \"Dry shipper use for air transport (not liquid nitrogen dewars)\",\n                    \"Real-time temperature monitoring (not just paper strips)\",\n                    \"Door-to-door hand-carry service\",\n                    \"Experience with your specific destination country\",\n                    \"Direct clinic-to-clinic coordination included\",\n                    \"Transparent, itemised pricing with no hidden fees\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"Red Flags to Avoid\",\n                text: \"Be cautious of couriers who cannot demonstrate IATA certification, offer cargo-hold-only transport, lack real-time monitoring, or have no experience with your destination's import requirements.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Questions to Ask Before Booking\",\n                text: \"A qualified courier will answer these without hesitation:\",\n                items: [\n                    \"Have you shipped to [destination country] before?\",\n                    \"What happens if my flight is delayed?\",\n                    \"Can my clinic track the shipment in real time?\",\n                    \"What documentation do you handle vs. what do I need to arrange?\",\n                    \"What is your cold chain incident protocol?\"\n                ]\n            },\n            {\n                type: \"cta\",\n                text: \"ARKGlobal is IATA-certified with real-time 5G monitoring on every shipment. We're happy to answer all your questions — no obligation required.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"What should I look for in an IVF courier?\",\n                answer: \"IATA P650 certification, dry shippers, real-time temperature monitoring, door-to-door hand-carry, and proven experience with your destination country.\"\n            },\n            {\n                question: \"Can I use a standard medical courier?\",\n                answer: \"No. Standard couriers lack IATA dangerous goods certification and cryogenic equipment. They cannot legally carry biological specimens on commercial airlines.\"\n            }\n        ]\n    },\n    {\n        slug: \"why-temperature-control-matters-embryo-shipping\",\n        title: \"Why Temperature Control Matters in Embryo Shipping\",\n        seoTitle: \"Why Temperature Control Matters in Embryo Shipping\",\n        metaDescription: \"Temperature control is the most critical factor in embryo shipping. Learn why cold chain integrity matters and how real-time monitoring protects viability.\",\n        category: \"Education\",\n        keywords: [\n            \"embryo shipping temperature\",\n            \"cold chain embryo transport\",\n            \"temperature control IVF\",\n            \"cryo shipping monitoring\"\n        ],\n        publishedDate: \"2026-01-15\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"In cryogenic courier work, temperature control isn't a nice-to-have — it's the entire job. A single cold chain break, even brief, can compromise embryo viability in ways that aren't visible until thaw.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"The Science Behind Temperature Sensitivity\",\n                text: \"Vitrified embryos exist in a glass-like state below -150°C. Above approximately -130°C, the material begins transitioning back, allowing ice crystals to form and damage cell membranes. The embryo may appear normal during thaw but fail at implantation.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"How Temperature Is Maintained\",\n                text: \"Professional embryo shipping relies on:\",\n                items: [\n                    \"Certified dry shippers charged to full capacity before collection\",\n                    \"Hand-carry transport avoiding cargo hold temperature extremes\",\n                    \"Route planning to minimise total transit time\",\n                    \"5G data loggers providing continuous real-time readings\",\n                    \"Contingency plans for customs delays or flight cancellations\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"Why Real-Time Monitoring Changes Everything\",\n                text: \"Historically, temperature was verified only at the destination — meaning problems were discovered after the fact. Real-time monitoring allows immediate action if a reading approaches a threshold, turning a potential failure into a manageable situation.\"\n            },\n            {\n                type: \"cta\",\n                text: \"Every ARKGlobal shipment includes 5G real-time temperature monitoring accessible to patients and clinics worldwide.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"What temperature must embryos stay at during shipping?\",\n                answer: \"Below -150°C. Vitrified embryos become unstable above approximately -130°C.\"\n            },\n            {\n                question: \"How is temperature monitored during embryo shipping?\",\n                answer: \"Professional couriers use electronic data loggers that continuously record and transmit internal temperature in real time.\"\n            }\n        ]\n    },\n    {\n        slug: \"ivf-sample-transportation-process-explained\",\n        title: \"IVF Sample Transportation Process Explained\",\n        seoTitle: \"IVF Sample Transportation Process Explained | Step by Step\",\n        metaDescription: \"A complete step-by-step guide to the IVF sample transportation process — from clinic paperwork to delivery, customs, and temperature handover.\",\n        category: \"Patient Guides\",\n        keywords: [\n            \"IVF sample transportation\",\n            \"fertility sample shipping process\",\n            \"embryo transport steps\",\n            \"cryo shipping workflow\"\n        ],\n        publishedDate: \"2026-02-01\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"Whether you're moving embryos, eggs, sperm, or stem cells, the IVF sample transportation process follows a consistent workflow designed to protect cold chain integrity and meet regulatory requirements at every stage.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Phase 1: Pre-Shipment (2–8 Weeks Before)\",\n                text: \"The preparation phase involves:\",\n                items: [\n                    \"Patient consent and clinic release documentation\",\n                    \"Receiving clinic acceptance confirmation\",\n                    \"Import permit application (destination-dependent)\",\n                    \"Courier booking and route planning\",\n                    \"Inter-clinic communication and handover protocol agreement\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"Phase 2: Shipment Day\",\n                text: \"On the day of transport, the courier collects the dry shipper from the sending clinic. The embryologist loads samples under supervision, seals the vessel, and activates the temperature data logger. The courier takes custody and proceeds to the airport.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Phase 3: In Transit\",\n                text: \"During flight and any connections, the data logger continuously transmits temperature data. Patients and both clinics can monitor via a tracking link. The courier remains with the dry shipper at all times.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Phase 4: Arrival and Handover\",\n                text: \"At the destination, the courier clears customs, delivers to the receiving clinic, and provides the complete temperature audit trail. The receiving embryologist verifies conditions before transferring samples to storage.\"\n            },\n            {\n                type: \"cta\",\n                text: \"ARKGlobal manages every phase of the IVF sample transportation process. Reach out at least 6–8 weeks before your planned date for destinations requiring import permits.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"How long does the IVF transportation process take?\",\n                answer: \"Preparation takes 2–8 weeks (permits). The physical shipment typically completes in 24–48 hours.\"\n            },\n            {\n                question: \"Who coordinates between the clinics?\",\n                answer: \"A specialist cryo courier like ARKGlobal handles inter-clinic communication, documentation, and logistics coordination as part of the service.\"\n            }\n        ]\n    },\n    {\n        slug: \"moving-your-fertility-journey-abroad\",\n        title: \"Moving Your Fertility Journey Abroad\",\n        seoTitle: \"Moving Your Fertility Journey Abroad | Transport Guide\",\n        metaDescription: \"Relocating abroad with frozen eggs or embryos? Learn how to move your fertility samples internationally — documentation, logistics, and planning tips.\",\n        category: \"Patient Guides\",\n        keywords: [\n            \"moving fertility samples abroad\",\n            \"egg transport relocation\",\n            \"embryo shipping relocation\",\n            \"fertility journey abroad\"\n        ],\n        publishedDate: \"2026-02-15\",\n        author: \"ARKGlobal\",\n        content: [\n            {\n                type: \"intro\",\n                text: \"More patients than ever are freezing eggs or embryos in one country and later moving to another — for work, family, or to continue treatment at a new clinic. Moving your fertility journey abroad is entirely possible with the right planning and logistics partner.\"\n            },\n            {\n                type: \"h2\",\n                heading: \"Common Scenarios\",\n                text: \"We regularly help patients in these situations:\",\n                items: [\n                    \"Frozen eggs at a Singapore or KL clinic, relocating to Australia or the UK\",\n                    \"Embryos created during IVF abroad, returning home for transfer\",\n                    \"Eggs frozen during expat assignment, moving to a new country permanently\",\n                    \"Couples splitting time between two countries who need samples at a specific clinic\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"What You Need to Arrange\",\n                text: \"Moving samples abroad requires:\",\n                items: [\n                    \"Consent documentation authorising the transfer\",\n                    \"Release letter from your current storage clinic\",\n                    \"Acceptance letter from your new clinic\",\n                    \"Import permit for the destination country\",\n                    \"An IATA-certified cryo courier for physical transport\"\n                ]\n            },\n            {\n                type: \"h2\",\n                heading: \"Planning Tips\",\n                text: \"Start planning at least 6–8 weeks before you need samples at the new clinic. Keep all paperwork from your freezing cycle. Choose a clinic with international transfer experience. Budget for transport separately — it's not included in fertility treatment packages.\"\n            },\n            {\n                type: \"cta\",\n                text: \"Moving abroad with frozen eggs or embryos? ARKGlobal can coordinate the entire transfer — contact us for a no-obligation consultation.\"\n            }\n        ],\n        faqs: [\n            {\n                question: \"Can I take my frozen eggs with me when I move abroad?\",\n                answer: \"Yes. With clinic release documentation, import permits, and an IATA-certified courier, frozen eggs can be transported to your new country and clinic.\"\n            },\n            {\n                question: \"How far in advance should I plan?\",\n                answer: \"At least 6–8 weeks, especially for destinations like Australia and the UK that require formal import permits.\"\n            }\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./src/lib/blog-posts-seo.ts\n");

